for /f "tokens=5" %%a in ('netstat -aon ^| findstr :3329') do (
    echo Killing process %%a on port 3329
    taskkill /F /PID %%a >nul 2>&1
)

echo.
echo ========================================
echo All services stopped!
echo ========================================
echo.
pause

